<?php
namespace App\Http\Controllers\PelakuUmkm;
use App\Http\Controllers\Controller;use App\Models\{Umkm,UmkmUpdateSubmission};use App\Services\Audit\AuditLogger;use Illuminate\Http\Request;
class PelakuUmkmController extends Controller { private function ownedUmkmQuery(Request $request){ return Umkm::query()->whereHas('userLinks',fn($q)=>$q->where('user_id',$request->user()->id)); } public function dashboard(Request $request){ $owned=$this->ownedUmkmQuery($request); return view('pages.pelaku-umkm.dashboard',['data'=>['owned_count'=>(clone $owned)->count(),'proposal_pending'=>UmkmUpdateSubmission::query()->where('submitted_by',$request->user()->id)->whereIn('status_data',['draft','diajukan','perlu_perbaikan'])->count(),'need_fix'=>UmkmUpdateSubmission::query()->where('submitted_by',$request->user()->id)->where('status_data','perlu_perbaikan')->count()]]); } public function profiles(Request $request){ return view('pages.pelaku-umkm.profiles',['umkms'=>$this->ownedUmkmQuery($request)->get(['id','umkm_code','business_name','status_data','quality_status'])]); } public function profileShow(Request $request, Umkm $umkm, AuditLogger $audit){ abort_unless($umkm->userLinks()->where('user_id',$request->user()->id)->exists(),403); $audit->log('umkm.owner.profile.view',$request,'umkms',$umkm->id); return view('pages.pelaku-umkm.profile-show',compact('umkm')); } public function proposalStatus(Request $request){ return view('pages.pelaku-umkm.proposal-status',['submissions'=>UmkmUpdateSubmission::query()->where('submitted_by',$request->user()->id)->latest()->paginate(20)]); } public function proposalFixForm(Request $request, UmkmUpdateSubmission $proposal){ abort_unless($proposal->submitted_by===$request->user()->id,403); abort_unless($proposal->status_data==='perlu_perbaikan',422); return view('pages.pelaku-umkm.proposal-fix',compact('proposal')); } public function proposalFixSubmit(Request $request, UmkmUpdateSubmission $proposal, AuditLogger $audit){ abort_unless($proposal->submitted_by===$request->user()->id,403); abort_unless($proposal->status_data==='perlu_perbaikan',422); $validated=$request->validate(['proposed_business_name'=>['nullable','string','max:150'],'proposed_quality_status'=>['nullable','string','max:50'],'proposed_notes'=>['nullable','string']]); $before=$proposal->toArray(); $newData=$proposal->new_data ?? []; $newData['business_name']=$validated['proposed_business_name'] ?? ($newData['business_name'] ?? null); $newData['quality_status']=$validated['proposed_quality_status'] ?? ($newData['quality_status'] ?? null); $newData['notes']=$validated['proposed_notes'] ?? ($newData['notes'] ?? null); $proposal->update(['new_data'=>$newData,'status_data'=>'diajukan','review_notes'=>null]); $audit->log('umkm.proposal.resubmit_after_fix',$request,'umkm_update_submissions',$proposal->id,$before,$proposal->fresh()->toArray()); return redirect()->route('pelaku-umkm.proposals.status')->with('status','Usulan perbaikan diajukan ulang.'); } public function survey(Request $request){ return view('pages.pelaku-umkm.survey',['targeted'=>true]); }}
